const b = $json.body || $json;

const rawPhone   = String(b.phone || b.whatsapp || '');
const nome       = String(b.name  || 'Lead').trim();
const segmento   = String(b.segment    || '');
const investment = String(b.investment || '');
const objetivo   = String(b.goal       || '');
const origem     = String(b.source     || 'hs-visual-quiz');
const ts         = b.timestamp || new Date().toISOString();

// E.164
let whatsapp = rawPhone.replace(/\D/g, '').replace(/^0+/, '');
if (!whatsapp.startsWith('55')) whatsapp = '55' + whatsapp;

// Normalizar para matching sem acentos
const norm = (s) => s.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
const segNorm = norm(segmento);
const invNorm = norm(investment);

// Score investimento
let iScore = 0;
if (invNorm.includes('3k') && invNorm.includes('10k')) iScore = 35;
else if (invNorm.includes('10k') && invNorm.includes('30k')) iScore = 65;
else if (invNorm.includes('30k') && invNorm.includes('80k')) iScore = 85;
else if (invNorm.includes('80k') || invNorm.includes('acima')) iScore = 100;
else if (invNorm.includes('3k') || invNorm.includes('ate')) iScore = 10;

// Score segmento
let sScore = 0;
if (segNorm.includes('imobil')) sScore = 25;
else if (segNorm.includes('saude')) sScore = 20;
else if (segNorm.includes('b2b') || segNorm.includes('corporate')) sScore = 20;
else if (segNorm.includes('lifestyle') || segNorm.includes('varejo')) sScore = 15;
else sScore = 5;

const score = Math.min(iScore + sScore, 100);
const tempEmoji = score >= 80 ? '🔴' : score >= 50 ? '🟡' : '🔵';
const tempLabel = score >= 80 ? 'HOT' : score >= 50 ? 'WARM' : 'COLD';
const firstName = nome.split(' ')[0];

// Mensagem personalizada ao lead
let base;
if (segNorm.includes('imobil')) {
  base = 'Ola ' + firstName + '! 🏠\n\nVi que voce atua com *imoveis de luxo* e seu objetivo e *' + objetivo + '*.' + '\n\n📈 Clientes do segmento imobiliario na HS Visual chegaram a +292% em leads qualificados. Voce esta no lugar certo!';
} else if (segNorm.includes('saude')) {
  base = 'Ola ' + firstName + '! 🏥\n\nVi que voce atua com *saude premium* e seu objetivo e *' + objetivo + '*.' + '\n\n📈 Clinicas parceiras da HS Visual triplicaram o numero de consultas em 90 dias.';
} else if (segNorm.includes('b2b') || segNorm.includes('corporate')) {
  base = 'Ola ' + firstName + '! 💼\n\nVi que voce atua no mercado *corporate* e seu objetivo e *' + objetivo + '*.' + '\n\n📈 Empresas B2B na HS Visual reduziram o ciclo de vendas em ate 40%.';
} else if (segNorm.includes('lifestyle') || segNorm.includes('varejo')) {
  base = 'Ola ' + firstName + '! ✨\n\nVi que voce atua no *lifestyle premium* e seu objetivo e *' + objetivo + '*.' + '\n\n📈 Marcas de alto padrao convertem ate 8x mais com conteudo de elite.';
} else {
  base = 'Ola ' + firstName + '! 👋\n\nVi que seu objetivo e *' + objetivo + '* — voce esta no lugar certo.';
}

const mensagem = base +
  '\n\n📊 *Proximo passo:* vou analisar seu perfil e te enviar um diagnostico personalizado em ate 24h.' +
  '\n\n💬 Me conta: qual e o maior desafio do seu marketing hoje?' +
  '\n\n_Helder Show — HS Visual | Jundiai/SP | hsvisual.com_';

// Alerta interno com emojis e espacamento
const horario = new Date(ts).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const alertMsg =
  '🚀 *NOVO LEAD QUALIFICADO!*\n\n' +
  '👤 *Nome:* ' + nome + '\n' +
  '🏢 *Segmento:* ' + segmento + '\n' +
  tempEmoji + ' *Score:* ' + score + '/100 — ' + tempLabel + '\n\n' +
  '📱 *WhatsApp:* wa.me/' + whatsapp + '\n' +
  '💰 *Investimento:* ' + investment + '\n' +
  '🎯 *Objetivo:* ' + objetivo + '\n\n' +
  '⏰ *Horario:* ' + horario;

return [{ json: {
  nome, firstName, whatsapp, segmento,
  investimento: investment, objetivo, origem,
  score, temperatura: tempLabel, mensagem, alertMsg,
  created_at: new Date().toISOString()
}}];
